import 'package:json_annotation/json_annotation.dart';
import 'search_criteria.dart';

part 'flight_result.g.dart';

/// Rich flight result from the search API.
/// @JsonSerializable(fieldRename: FieldRename.snake):
///   priceInr → 'price_inr', durationMinutes → 'duration_minutes', etc.
/// The .g.dart file is pre-generated by the lesson script.
/// In production: flutter pub run build_runner build
@JsonSerializable(fieldRename: FieldRename.snake, explicitToJson: true)
final class FlightResult {
  const FlightResult({
    required this.id,
    required this.airline,
    required this.airlineCode,
    required this.flightNumber,
    required this.origin,
    required this.destination,
    required this.departureTime,
    required this.arrivalTime,
    required this.durationMinutes,
    required this.priceInr,
    required this.stops,
    required this.cabinClass,
    required this.seatsLeft,
    required this.baggageAllowance,
    required this.isRefundable,
  });

  final String   id;
  final String   airline;
  final String   airlineCode;
  final String   flightNumber;
  final String   origin;
  final String   destination;
  final DateTime departureTime;
  final DateTime arrivalTime;
  final int      durationMinutes;
  final double   priceInr;
  final int      stops;
  final CabinClass cabinClass;
  final int      seatsLeft;
  final String   baggageAllowance;
  final bool     isRefundable;

  String get stopsLabel =>
      stops == 0 ? 'Non-stop' : '$stops stop${stops == 1 ? '' : 's'}';
  String get formattedPrice =>
      '₹${priceInr.toStringAsFixed(0)}';
  String get formattedDuration {
    final h = durationMinutes ~/ 60;
    final m = durationMinutes  % 60;
    return m == 0 ? '${h}h' : '${h}h ${m}m';
  }
  String get accessibilityLabel =>
      '$airline $flightNumber, $origin to $destination, '
      '$formattedPrice, $stopsLabel, $formattedDuration';

  factory FlightResult.fromJson(Map<String, dynamic> json) =>
      _$FlightResultFromJson(json);
  Map<String, dynamic> toJson() => _$FlightResultToJson(this);
}
